import{_ as r,o as e,c as t,ag as i}from"./chunks/framework.ETe_P6d1.js";const o="/kaiping-reports/assets/1.CWWx1UCO.jpg",s="/kaiping-reports/assets/2.DIYaq3BM.jpg",l="/kaiping-reports/assets/3.qUc-0QHe.jpg",h="/kaiping-reports/assets/4.DEvkOJRw.jpg",n="/kaiping-reports/assets/5.DSVXn3QA.jpg",p="/kaiping-reports/assets/6.BrVbwCPt.jpg",d="/kaiping-reports/assets/7.j2tIAPEe.jpg",c="/kaiping-reports/assets/8.XTG-t_eS.jpg",_="/kaiping-reports/assets/9.DLAonXKN.jpg",m="/kaiping-reports/assets/10.Df9gNo8V.jpg",u="/kaiping-reports/assets/11.DO2Nf434.jpg",b="/kaiping-reports/assets/12.CS08etWa.jpg",q="/kaiping-reports/assets/13.BKh0aRD8.jpg",T=JSON.parse('{"title":"多维视角下开平建筑研究调研报告","description":"","frontmatter":{"title":"多维视角下开平建筑研究调研报告"},"headers":[],"relativePath":"reports/汪雨萱/汪雨萱_关于开平侨乡建筑研究的调研报告.md","filePath":"reports/汪雨萱/汪雨萱_关于开平侨乡建筑研究的调研报告.md"}'),g={name:"reports/汪雨萱/汪雨萱_关于开平侨乡建筑研究的调研报告.md"};function k(f,a,P,x,j,D){return e(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="多维视角下开平建筑研究调研报告" tabindex="-1">多维视角下开平建筑研究调研报告 <a class="header-anchor" href="#多维视角下开平建筑研究调研报告" aria-label="Permalink to &quot;多维视角下开平建筑研究调研报告&quot;">​</a></h1><h1 id="课程名称" tabindex="-1">课程名称 <a class="header-anchor" href="#课程名称" aria-label="Permalink to &quot;课程名称&quot;">​</a></h1><h1 id="课程负责人" tabindex="-1">课程负责人 <a class="header-anchor" href="#课程负责人" aria-label="Permalink to &quot;课程负责人&quot;">​</a></h1><h1 id="实习日期" tabindex="-1">实习日期 <a class="header-anchor" href="#实习日期" aria-label="Permalink to &quot;实习日期&quot;">​</a></h1><h1 id="学生所在学院" tabindex="-1">学生所在学院 <a class="header-anchor" href="#学生所在学院" aria-label="Permalink to &quot;学生所在学院&quot;">​</a></h1><h1 id="专业或班级" tabindex="-1">专业或班级 <a class="header-anchor" href="#专业或班级" aria-label="Permalink to &quot;专业或班级&quot;">​</a></h1><h1 id="学生姓名" tabindex="-1">学生姓名 <a class="header-anchor" href="#学生姓名" aria-label="Permalink to &quot;学生姓名&quot;">​</a></h1><h1 id="学生学号" tabindex="-1">学生学号 <a class="header-anchor" href="#学生学号" aria-label="Permalink to &quot;学生学号&quot;">​</a></h1><h1 id="带队教师" tabindex="-1">带队教师 <a class="header-anchor" href="#带队教师" aria-label="Permalink to &quot;带队教师&quot;">​</a></h1><hr><h1 id="专业调研报告内容" tabindex="-1">专业调研报告内容 <a class="header-anchor" href="#专业调研报告内容" aria-label="Permalink to &quot;专业调研报告内容&quot;">​</a></h1><h3 id="开平建筑调研报告" tabindex="-1">开平建筑调研报告 <a class="header-anchor" href="#开平建筑调研报告" aria-label="Permalink to &quot;开平建筑调研报告&quot;">​</a></h3><p>本次调研前往江门开平赤坎、塘口、立园等地，主要观察侨乡特色建筑，包括骑楼、碉楼、侨乡民居与园林空间。现场讲解中提到的寻根文化、乡愁、乡村振兴让人印象深刻。</p><h1 id="考察地点" tabindex="-1">考察地点 <a class="header-anchor" href="#考察地点" aria-label="Permalink to &quot;考察地点&quot;">​</a></h1><h1 id="考察时间" tabindex="-1">考察时间 <a class="header-anchor" href="#考察时间" aria-label="Permalink to &quot;考察时间&quot;">​</a></h1><h1 id="考察人员" tabindex="-1">考察人员 <a class="header-anchor" href="#考察人员" aria-label="Permalink to &quot;考察人员&quot;">​</a></h1><h1 id="考察主题" tabindex="-1">考察主题 <a class="header-anchor" href="#考察主题" aria-label="Permalink to &quot;考察主题&quot;">​</a></h1><hr><h1 id="一、为什么是开平-不只是看老房子" tabindex="-1">一、为什么是开平：不只是看老房子 <a class="header-anchor" href="#一、为什么是开平-不只是看老房子" aria-label="Permalink to &quot;一、为什么是开平：不只是看老房子&quot;">​</a></h1><p>这次去开平，初衷是学习岭南近代建筑。作为一个环境设计的学生，平时在学校更多是在图纸和模型里推敲空间，但建筑作为一个确切的实体可以承载一段历史的记忆。所以当真正站在赤坎古镇的骑楼街下，或者走进仓东村那座安静的老祠堂时，我才对“建筑的文化厚度”有了具象的认知。</p><p>本次考察以开平赤坎古镇及周边侨乡村落为主要对象，是对岭南近代侨乡建筑、历史文化与乡村振兴实践的系统性实地学习。开平作为著名侨乡，拥有大量骑楼、碉楼、祠堂、西式洋楼与传统民居，建筑风格高度融合中西，既保留岭南本土营造技艺，又吸收海外建筑形式，是近代华侨历史、宗族文化与乡土生活的重要物质见证。</p><p>开平最打动我的，不是建筑形式有多华丽，而是那种中西混杂的坦荡，以及背后承载的寻根情结。这两天的行程，赤坎展示了商业与生活的历史截面，而仓东村则把乡愁和宗族记忆铺陈在眼前。这份报告，是我作为一个初学者的观察笔记，试图梳理这些砖瓦木石背后，除了形态、构造之外的人情味。</p><p><img src="'+o+'" alt=""><img src="'+s+'" alt=""></p><hr><h1 id="二、空间笔记-几种典型建筑的身体感受" tabindex="-1">二、空间笔记：几种典型建筑的身体感受 <a class="header-anchor" href="#二、空间笔记-几种典型建筑的身体感受" aria-label="Permalink to &quot;二、空间笔记：几种典型建筑的身体感受&quot;">​</a></h1><h3 id="_1-骑楼-为行人撑起一把伞的线性城市" tabindex="-1">1. 骑楼：为行人撑起一把伞的线性城市 <a class="header-anchor" href="#_1-骑楼-为行人撑起一把伞的线性城市" aria-label="Permalink to &quot;1. 骑楼：为行人撑起一把伞的线性城市&quot;">​</a></h3><p>赤坎的骑楼群沿潭江铺开，那种连绵的柱廊特别有秩序感。底层往里一退，就形成了一个半室外的灰空间。那天太阳很晒，走进廊下立刻凉快了。这种设计非常岭南——它不是为了造型而造型，完全是为了适应多雨暴晒的气候，让商业活动能风雨无阻地进行。从专业角度看，这种“下店上住”的联排模式，用最集约的沿街面解决了商住混合的问题。现在改造后，楼下开着咖啡馆和文创店，游客在廊道里穿梭，历史的骨架没变，但里面流动的是当下的生活，这种新旧交织的状态让我觉得老建筑并没有死掉。</p><p>赤坎古镇最具代表性的就是骑楼建筑群。骑楼沿河岸连续排布，形成完整街道界面，是典型的岭南滨水商业空间。建筑多为二至三层，底层采用柱廊形式，形成遮阳避雨的公共步行通道，适合南方多雨湿热气候。二层及以上为居住空间，窗户多为拱券式，立面装饰简洁又富有层次。</p><h3 id="_2-碉楼与洋楼-防御与炫耀的双面体" tabindex="-1">2. 碉楼与洋楼：防御与炫耀的双面体 <a class="header-anchor" href="#_2-碉楼与洋楼-防御与炫耀的双面体" aria-label="Permalink to &quot;2. 碉楼与洋楼：防御与炫耀的双面体&quot;">​</a></h3><p>如果说骑楼是温情的商业街，那碉楼就是带刺的玫瑰。它们往往瘦高、窗小、墙厚，视觉上很有压迫感。但在最顶部，又突然出现西式的柱式、山花或者拱券。我当时在想，这其实是一种很复杂的心理映射：早年华侨在海外打拼，回到家乡最缺的是安全感（防御匪患），但同时又想展示自己见过世面、有经济实力（炫耀）。于是，钢筋混凝土的坚固躯干上，顶着一顶西洋礼帽。这种土洋结合不刻意、不矫情，是一种非常直白的生存智慧表达。</p><p>碉楼是开平最具标识性的建筑类型，多为高层砖石或混凝土结构，墙体厚实、开窗狭小，兼具防御、瞭望、居住功能。</p><h3 id="_3-祠堂与祖屋-精神上的坐标原点" tabindex="-1">3. 祠堂与祖屋：精神上的坐标原点 <a class="header-anchor" href="#_3-祠堂与祖屋-精神上的坐标原点" aria-label="Permalink to &quot;3. 祠堂与祖屋：精神上的坐标原点&quot;">​</a></h3><p>仓东村的体验是完全不同的。那里很安静，建筑尺度也回到了人的尺度。祠堂的中轴对称、青砖的素雅，让人不由自主就放低了声音。在我们到目的地不久时，当地的老师讲解时提到“寻根”，我站在天井里看着那些斑驳的木门，才明白：对于远渡重洋的华侨后代来说，这栋具体的房子、这个具体的门槛，就是抽象故乡的唯一物理证据。</p><p>这类建筑不仅是物理空间，更是家族凝聚力、传统礼仪、乡土信仰的载体。对于海外华侨而言，祠堂和祖屋是“根”的象征，是身份认同、家族记忆和文化归属的核心。</p><h3 id="_4-传统民居与乡土空间-真实的乡村肌理" tabindex="-1">4. 传统民居与乡土空间：真实的乡村肌理 <a class="header-anchor" href="#_4-传统民居与乡土空间-真实的乡村肌理" aria-label="Permalink to &quot;4. 传统民居与乡土空间：真实的乡村肌理&quot;">​</a></h3><p>村落中保留大量传统民居，以青砖、木构、坡屋顶为主，院落紧凑、尺度亲切，顺应地形与水系布局。民居内部天井、厅堂、灶台、旧家具等细节，保留着浓厚生活气息。这些建筑看似普通，却是乡村生活最真实的记录，也是“乡愁”最具体的载体。</p><p><img src="'+l+'" alt=""></p><p>整体来看，开平侨乡建筑空间呈现三大特点：一是沿水布局、街巷有序，顺应自然环境；二是功能复合、公私结合，居住、商业、公共活动相互渗透；三是中西融合、新旧并置，传统形制与西式元素共存，历史建筑与现代改造空间共生。</p><p><img src="'+h+'" alt=""><img src="'+n+'" alt=""><img src="'+p+'" alt=""></p><hr><h1 id="三、材料与构造-民间工匠的务实美学" tabindex="-1">三、材料与构造：民间工匠的务实美学 <a class="header-anchor" href="#三、材料与构造-民间工匠的务实美学" aria-label="Permalink to &quot;三、材料与构造：民间工匠的务实美学&quot;">​</a></h1><p>开平的房子在用料上特别务实，没有太多矫饰，但细节里都是功夫。</p><p><img src="'+d+'" alt=""></p><h1 id="材料" tabindex="-1">材料 <a class="header-anchor" href="#材料" aria-label="Permalink to &quot;材料&quot;">​</a></h1><h1 id="构造巧思" tabindex="-1">构造巧思 <a class="header-anchor" href="#构造巧思" aria-label="Permalink to &quot;构造巧思&quot;">​</a></h1><hr><h1 id="四、活化的启示-让老房子继续-活着" tabindex="-1">四、活化的启示：让老房子继续“活着” <a class="header-anchor" href="#四、活化的启示-让老房子继续-活着" aria-label="Permalink to &quot;四、活化的启示：让老房子继续“活着”&quot;">​</a></h1><p>这次考察也让我在思考，学设计将来能为这些老建筑做些什么。</p><p>开平目前的做法我挺认同的，叫 <strong>“轻改造、重活化”</strong>。<br> 在赤坎，他们把危房加固，管线入地，但保留了斑驳的墙面和狭窄的楼梯。植入的新功能（民宿、展厅、糖水铺）都是现代人需要的，但空间的骨架还是百年前的样子。</p><p>对比之下，仓东村走得更慢、更温情。那里没有浓重的商业味，反而更像一个教育基地。他们修复祠堂不是为了收门票，而是为了让海外的族人回来时，能有一间完好的祖屋可以上炷香。</p><p><img src="'+c+'" alt=""></p><p>这对我启发很大。乡村设计最难的不是画出一张漂亮的改造图，而是搞清楚 <strong>“谁还会回来用这个空间”</strong>。如果建筑只是被当成标本供起来，它和人的情感连接就断了。真正的活化，应该是让建筑被需要、被使用、被后人爱惜。</p><p><img src="'+_+'" alt=""></p><hr><h1 id="五、关于-寻根-建筑作为情感的载体" tabindex="-1">五、关于“寻根”：建筑作为情感的载体 <a class="header-anchor" href="#五、关于-寻根-建筑作为情感的载体" aria-label="Permalink to &quot;五、关于“寻根”：建筑作为情感的载体&quot;">​</a></h1><p>这两天听讲解，听得最多的词是“根”。以前我觉得这是个很虚的概念，但在开平，根就是实实在在的瓦片和门牌。</p><p>很多华侨在国外出生长大，一句开平话都不会说，但当他站在这座外墙长着青苔的老宅前，他知道这是爷爷出发的地方。这种身份的确认感，是任何现代高楼都给不了的。这让我意识到，环境设计有时候是在设计一种容器，用来安放那些看不见摸不着但极其重要的东西——比如记忆、乡愁和归属感。</p><p><img src="'+m+'" alt=""><img src="'+u+'" alt=""></p><hr><h1 id="六、一点不成熟的思考与问题" tabindex="-1">六、一点不成熟的思考与问题 <a class="header-anchor" href="#六、一点不成熟的思考与问题" aria-label="Permalink to &quot;六、一点不成熟的思考与问题&quot;">​</a></h1><ol><li><strong>商业的同质化</strong>：赤坎有些店铺卖的东西和全国古镇如出一辙，怎么把“侨乡”这个IP做得更深、更有辨识度，是个难题。文创若是没有自己独特的点，很难吸引人们的向往。</li><li><strong>日常性的缺失</strong>：除了核心景区，稍偏一点的村子很安静，甚至空心化。靠节假日旅游能养活的建筑是有限的，怎么让年轻人愿意回来日常居住？</li><li><strong>设计的度</strong>：有些新建的配套建筑，虽然用了青砖，但总觉得气质不对。怎么在创新时保持那种“拙朴”的乡土感，我还需要花很长时间去学习。</li></ol><p><img src="'+b+'" alt=""><img src="'+q+'" alt=""></p><hr><h1 id="七、结语" tabindex="-1">七、结语 <a class="header-anchor" href="#七、结语" aria-label="Permalink to &quot;七、结语&quot;">​</a></h1><p>作为一个大二的学生，这次开平之行像一堂生动的校外专业课。它告诉我，好的设计是长出来的，不是凭空画出来的。赤坎的骑楼、仓东的祠堂，它们的美不在于某一个惊世骇俗的造型，而在于对气候的适应、对生活的包容、对血脉的回应。</p><p>未来的设计路上，我希望自己能记住开平老墙上的那片光影。做设计不仅要考虑功能和审美，更要去理解那块土地上的历史和人心。让乡愁有处可依，让寻根有路可走，这或许就是侨乡建筑给我最深的专业启蒙。</p><hr><h1 id="指导教师意见" tabindex="-1">指导教师意见 <a class="header-anchor" href="#指导教师意见" aria-label="Permalink to &quot;指导教师意见&quot;">​</a></h1><ul><li>调研主目的意义：</li><li>调研过程与内容：</li><li>调研分析深度与专业适配性：</li><li>心得体会与反思：</li><li>总分：</li></ul><p>签名：<br> 年 月 日</p><hr><h1 id="说明" tabindex="-1">说明 <a class="header-anchor" href="#说明" aria-label="Permalink to &quot;说明&quot;">​</a></h1><ol><li>专业调研报告字数不少于2500字，页数不够可以自行加页，但不能更改表格格式。</li><li>开题报告字体为小四号，宋体（英文需用Times New Roman字体），行距为固定值20磅。</li><li>彩色双面打印。</li></ol>',73)])])}const N=r(g,[["render",k]]);export{T as __pageData,N as default};
